def path(s, t, max_h=4):
    q = deque([(s, [s])])
    seen = {s}
    while q:
        n, p = q.popleft()
        if n == t:
            return p
        if len(p) > max_h:
            continue
        for m in sorted(adj[n]):
            if m not in seen:
                seen.add(m)
